#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int x, y, z; scanf("%d %d %d", &x, &y, &z);
        int m = x; if(y < m) m = y; if(z < m) m = z;
        int cnt = 0; if(x == m) cnt++; if(y == m) cnt++; if(z == m) cnt++;
        printf("%s\n", cnt >= 2 ? "YES" : "NO");
    }
    return 0;
}

